import React, { useState } from 'react'
import { Link as RouterLink } from 'react-router-dom'
import { Link as ScrollLink } from "react-scroll";
import styled from "styled-components";
import Brand from "./Brand";

const Nav = React.memo(({ hamburgerState, setHamburgerState }) => {
  
  const handleHamburgerClick = () => {
    setHamburgerState(!hamburgerState)
  }

  return (
    <NavContainer>
      <RouterLink to="/">
        <Brand />
      </RouterLink>

      <div style={{ display: "flex", alignItems: "center", columnGap: "5em" }}>
        <NavLinks active={hamburgerState}>
          <li>
            <ScrollLink to="Projects" smooth={true} duration={500} onClick={() => setHamburgerState(false)}>
              Projects
            </ScrollLink>
          </li>
          <li>
            <ScrollLink to="Contact" smooth={true} duration={500} onClick={() => setHamburgerState(false)}>
              Contact
            </ScrollLink>
          </li>
        </NavLinks>
        
        <Hamburger active={hamburgerState} onClick={handleHamburgerClick}>
          <span /><span /><span />
        </Hamburger>
      </div>
    </NavContainer>
  )
});

const NavContainer = styled.nav`
  grid-column: 1/3;
  display: flex;
  justify-content: space-between;
  padding: 2em;

  position: sticky;

  & img {
    filter: invert(1);
    width: 2em;
    height: 2em;
  }
`

const Hamburger = styled.button`
  background: transparent;
  border: 0;
  cursor: pointer;
  width: 3em;
  height: 2em;

  position: relative;

  & > span {
    left: 0;
    display: block;
    width: 100%;
    height: 3px;
    position: absolute;
    
    background: white;
    border-radius: 3px;

    transition: 150ms;
    transition-delay: 150ms;

    &:first-of-type {
      top: 0%;
      ${props => props.active && "top: 50%; transition-delay: 0ms"}
    }

    &:nth-of-type(2) {
      top: 50%;
    }

    &:last-of-type {
      top: 100%;
      ${props => props.active && "top: 50%; transition-delay: 0ms"}
    }
  }
`

const NavLinks = styled.ul`
  padding: 0;
  margin: 0;
  transition: 150ms ease-out;

  opacity: 0;
  display: flex;
  column-gap: 2em;

  & li a {
    cursor: pointer;
    padding: 1em;
  }

  ${props => props.active && "opacity: 1"}
`

export default Nav
